/*
 * OvertimeReport Excel Add-in — Main Task Pane Logic
 * Phases 1–5: Sheet1, Pivot Sheets, Dashboard Pivots, KPI Cards, Top Performers, Charts
 */

/* global console, document, Excel, Office, fetch, Chart */

// ─── CONFIG (never commit real key) ──────────────────────────────────────────
const CONFIG = {
  CLAUDE_API_KEY: "sk-ant-YOUR-KEY-HERE", // replace before use; add src/config.js to .gitignore
};

// ─── CONSTANTS ────────────────────────────────────────────────────────────────
const ROLE_MECH_BASE = "MECHANIC - BaSE";
const ROLE_MECH_AUTO = "MECHANIC - AUTO"; // excluded everywhere

// 0-based column indices for the 26-column Sheet1 layout:
// RRDD | Home Ctr | Name | Employee ID | PPE Date | Work Ctr | Work Activity
// | ST Hrs | ST Amt | OT Hrs | OT Amt | DT Hrs | DT Amt | OT/DT Hrs | OT/DT Amt
// | Flat Amt | Total Amt | FT/PT CD | Job Class CD | ACCT | JOB_CLS_CD_DSC_TE
// | Region | District | JOB_FCT_CD | FUNCTION | Year
const COL = {
  REGION: 0,      // RRDD
  NAME: 2,        // Name
  PPE_DATE: 4,    // PPE Date
  ST: 7,          // ST Hrs
  ST_PAY: 8,      // ST Amt
  OT: 9,          // OT Hrs
  OT_PAY: 10,     // OT Amt
  DT: 11,         // DT Hrs
  DT_PAY: 12,     // DT Amt
  ROLE: 24,        // FUNCTION
};
const NUM_RAW_COLS = 26; // total columns in Sheet1

// ─── PIVOT FILTER STATE ──────────────────────────────────────────────────────
let _pivotWeek25 = ""; // selected 2025 week (formatted date string), "" = all
let _pivotWeek26 = ""; // selected 2026 week (formatted date string), "" = all
let _pivotFilterBusy = 0;
let _pivotEventRegistered = false;

// ─── OFFICE READY ─────────────────────────────────────────────────────────────
Office.onReady((info) => {
  if (info.host === Office.HostType.Excel) {
    document.getElementById("sideload-msg").style.display = "none";
    document.getElementById("app-body").style.display = "flex";

    document.getElementById("btn-refresh").onclick = refreshAll;
    document.getElementById("btn-style").onclick = applySheetTheme;
    document.getElementById("filterType").onchange = onFilterTypeChange;
    document.getElementById("filterValue").onchange = onFilterValueChange;

    // Initialize on load
    refreshAll();
  }
});

// ─── STEP 2: ENSURE RAW DATA SHEET EXISTS ────────────────────────────────────
// User pastes in pre-formatted 26-column data with its own headers.
// We just ensure the sheet exists and freeze the header row.
export async function createDataSheet() {
  await Excel.run(async (context) => {
    const sheets = context.workbook.worksheets;
    sheets.load("items/name");
    await context.sync();

    const exists = sheets.items.some((s) => s.name === "Sheet1");
    let sheet;
    if (exists) {
      sheet = sheets.getItem("Sheet1");
    } else {
      sheet = sheets.add("Sheet1");
    }

    // Style header row (row 1) if data is present
    const usedRange = sheet.getUsedRange();
    usedRange.load("rowCount");
    await context.sync();

    if (usedRange.rowCount >= 1) {
      const headerRange = sheet.getRange("1:1");
      headerRange.format.font.bold = true;
      headerRange.format.fill.color = "#1F3864";
      headerRange.format.font.color = "white";
    }

    sheet.freezePanes.freezeRows(1);
    sheet.activate();

    await context.sync();
  });
}

// ─── PIVOT TIME FILTER HELPER ────────────────────────────────────────────────
// (pivot filter helpers removed — week filters applied inline in writeProfessionalPivot)

// ─── SHARED: PROFESSIONAL PIVOT SHEET WRITER (Handsontable style) ────────────
async function writeProfessionalPivot(context, sheetName, role, rawData) {
  const filtered = rawData.filter((r) => r.role === role);

  // ── Extract unique weeks per year ───────────────────────────────────────────
  const allDates = filtered.map(r => r.ppeDate).filter(Boolean).sort((a, b) => a - b);
  const weeks25 = [...new Set(allDates.filter(d => d.getFullYear() !== 2026).map(d => formatDate(d)))];
  const weeks26 = [...new Set(allDates.filter(d => d.getFullYear() === 2026).map(d => formatDate(d)))];

  // Validate current selections (reset if value no longer in data)
  if (_pivotWeek25 && !weeks25.includes(_pivotWeek25)) _pivotWeek25 = "";
  if (_pivotWeek26 && !weeks26.includes(_pivotWeek26)) _pivotWeek26 = "";

  // Default to latest week if not set
  if (!_pivotWeek25 && weeks25.length > 0) _pivotWeek25 = weeks25[weeks25.length - 1];
  if (!_pivotWeek26 && weeks26.length > 0) _pivotWeek26 = weeks26[weeks26.length - 1];

  // ── Group by Region/District with independent year filtering ────────────────
  // 2025 data: filter by selected 2025 week (if set)
  // 2026 data: filter by selected 2026 week (if set)
  const regionMap = {};
  for (const r of filtered) {
    const key = r.region || "(No Region)";
    if (!regionMap[key])
      regionMap[key] = {
        region: key,
        st25: 0, ot25: 0, dt25: 0, stPay25: 0, otPay25: 0, dtPay25: 0,
        st26: 0, ot26: 0, dt26: 0, stPay26: 0, otPay26: 0, dtPay26: 0,
      };
    const year = r.ppeDate ? r.ppeDate.getFullYear() : 2025;
    const weekStr = r.ppeDate ? formatDate(r.ppeDate) : "";
    if (year === 2026) {
      if (_pivotWeek26 && weekStr !== _pivotWeek26) continue;
      regionMap[key].st26 += r.st;
      regionMap[key].ot26 += r.ot;
      regionMap[key].dt26 += r.dt;
      regionMap[key].stPay26 += r.stPay;
      regionMap[key].otPay26 += r.otPay;
      regionMap[key].dtPay26 += r.dtPay;
    } else {
      if (_pivotWeek25 && weekStr !== _pivotWeek25) continue;
      regionMap[key].st25 += r.st;
      regionMap[key].ot25 += r.ot;
      regionMap[key].dt25 += r.dt;
      regionMap[key].stPay25 += r.stPay;
      regionMap[key].otPay25 += r.otPay;
      regionMap[key].dtPay25 += r.dtPay;
    }
  }
  const regions = Object.values(regionMap).sort((a, b) => a.region.localeCompare(b.region));

  const totals = regions.reduce(
    (acc, g) => ({
      st25: acc.st25 + g.st25,
      ot25: acc.ot25 + g.ot25,
      dt25: acc.dt25 + g.dt25,
      st26: acc.st26 + g.st26,
      ot26: acc.ot26 + g.ot26,
      dt26: acc.dt26 + g.dt26,
      stPay25: acc.stPay25 + g.stPay25,
      otPay25: acc.otPay25 + g.otPay25,
      dtPay25: acc.dtPay25 + g.dtPay25,
      stPay26: acc.stPay26 + g.stPay26,
      otPay26: acc.otPay26 + g.otPay26,
      dtPay26: acc.dtPay26 + g.dtPay26,
    }),
    {
      st25: 0,
      ot25: 0,
      dt25: 0,
      st26: 0,
      ot26: 0,
      dt26: 0,
      stPay25: 0,
      otPay25: 0,
      dtPay25: 0,
      stPay26: 0,
      otPay26: 0,
      dtPay26: 0,
    }
  );

  // Ensure sheet exists and clear
  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  let sheet;
  const exists = sheets.items.some((s) => s.name === sheetName);
  if (exists) {
    sheet = sheets.getItem(sheetName);
    sheet.getUsedRange().clear();
  } else {
    sheet = sheets.add(sheetName);
  }

  const roleLabel = "MECHANIC BASE";

  // ── Color palette ─────────────────────────────────────────────────────────────
  const TITLE_BG   = "#1A3A2A";  // dark forest green — title background
  const SUB_BG     = "#FFFBEB";  // light amber — section headings background
  const SUB_TEXT   = "#8B5E00";  // golden brown — section heading text
  const HDR_FILL   = "#374151";  // charcoal — column headers
  const BODY_TEXT  = "#111827";  // near black — body text
  const BORDER_CLR = "#E5E7EB";  // light gray — borders
  const ALT_FILL   = "#F9FAFB";  // very light gray — alternating rows
  const YR25       = "#374151";  // charcoal — 2025 (historical)
  const YR26       = "#1B3560";  // dark navy — 2026 (current)
  const YR_DELTA   = "#1A3A2A";  // dark forest green — change indicator
  const KV_TEXT    = "#16A34A";  // emerald — totals text
  const KV_FILL    = "#F0FDF4";  // light green — totals fill

  // Column layout (A:U = 21 cols):
  // Hours: A=RR/DD | B-D=2025 ST/OT/DT | E-G=2026 ST/OT/DT | H-J=△ST/OT/DT
  // K=spacer
  // Pay:   L=RR/DD | M-O=2025 Pay | P-R=2026 Pay | S-U=△ST/OT/DT Pay

  // Border helper
  const setBorders = (range, color) => {
    const bc = color || BORDER_CLR;
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.thin;
      b.getItem(edge).color = bc;
    }
    try {
      b.getItem("InsideHorizontal").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideHorizontal").color = bc;
      b.getItem("InsideVertical").style = Excel.BorderLineStyle.thin;
      b.getItem("InsideVertical").color = bc;
    } catch (_) {
      /* single-cell ranges don't have inside borders */
    }
  };

  const setOuterBorder = (range, color) => {
    const b = range.format.borders;
    for (const edge of ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight"]) {
      b.getItem(edge).style = Excel.BorderLineStyle.medium;
      b.getItem(edge).color = color || "#111827";
    }
  };

  // ── Row 1: Title ──────────────────────────────────────────────────────────────
  const titleRange = sheet.getRange("A1:U1");
  titleRange.merge(false);
  sheet.getRange("A1").values = [[`${roleLabel} OVERTIME REPORT`]];
  sheet.getRange("A1").format.font.bold = true;
  sheet.getRange("A1").format.font.size = 14;
  sheet.getRange("A1").format.font.color = "white";
  sheet.getRange("A1").format.font.name = "Segoe UI";
  titleRange.format.fill.color = TITLE_BG;
  titleRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  titleRange.format.verticalAlignment = Excel.VerticalAlignment.center;
  titleRange.format.rowHeight = 34;

  // ── Row 2: Two Week Filter Dropdowns ──────────────────────────────────────────
  const row2All = sheet.getRange("A2:U2");
  row2All.format.fill.color = SUB_BG;
  row2All.format.rowHeight = 22;
  row2All.format.verticalAlignment = Excel.VerticalAlignment.center;
  setBorders(row2All, BORDER_CLR);

  // A2: "2025 WEEK" label
  const a2 = sheet.getRange("A2");
  a2.values = [["2025 WEEK"]];
  a2.format.font.bold = true;
  a2.format.font.size = 8;
  a2.format.font.color = SUB_TEXT;
  a2.format.font.name = "Segoe UI";
  a2.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // B2: 2025 week dropdown
  const b2 = sheet.getRange("B2");
  b2.dataValidation.clear();
  if (weeks25.length > 0) {
    const opts25 = weeks25.map(v => [v]);
    sheet.getRange(`W1:W${weeks25.length}`).values = opts25;
    b2.dataValidation.rule = {
      list: { inCellDropDown: true, source: `=$W$1:$W$${weeks25.length}` }
    };
    b2.values = [[_pivotWeek25 || weeks25[weeks25.length - 1]]];
  } else {
    b2.values = [["No data"]];
  }
  b2.format.font.size = 9;
  b2.format.font.name = "Segoe UI";
  b2.format.font.color = BODY_TEXT;
  b2.format.fill.color = "#FFFFFF";
  b2.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  setBorders(b2, "#A0AABB");

  // D2: "2026 WEEK" label  (C2 left empty as spacer)
  const d2 = sheet.getRange("D2");
  d2.values = [["2026 WEEK"]];
  d2.format.font.bold = true;
  d2.format.font.size = 8;
  d2.format.font.color = SUB_TEXT;
  d2.format.font.name = "Segoe UI";
  d2.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // E2: 2026 week dropdown
  const e2 = sheet.getRange("E2");
  e2.dataValidation.clear();
  if (weeks26.length > 0) {
    const opts26 = weeks26.map(v => [v]);
    sheet.getRange(`X1:X${weeks26.length}`).values = opts26;
    e2.dataValidation.rule = {
      list: { inCellDropDown: true, source: `=$X$1:$X$${weeks26.length}` }
    };
    e2.values = [[_pivotWeek26 || weeks26[weeks26.length - 1]]];
  } else {
    e2.values = [["No data"]];
  }
  e2.format.font.size = 9;
  e2.format.font.name = "Segoe UI";
  e2.format.font.color = BODY_TEXT;
  e2.format.fill.color = "#FFFFFF";
  e2.format.horizontalAlignment = Excel.HorizontalAlignment.center;
  setBorders(e2, "#A0AABB");

  // H2:J2: Period info (merged)
  const periodRange = sheet.getRange("H2:J2");
  periodRange.merge(false);
  const periodLabel = `${_pivotWeek25 || "All 2025"}  vs  ${_pivotWeek26 || "All 2026"}`;
  sheet.getRange("H2").values = [[periodLabel]];
  sheet.getRange("H2").format.font.size = 9;
  sheet.getRange("H2").format.font.italic = true;
  sheet.getRange("H2").format.font.color = SUB_TEXT;
  sheet.getRange("H2").format.font.name = "Segoe UI";
  periodRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;

  // ── Row 3: Spacer ─────────────────────────────────────────────────────────────
  sheet.getRange("A3:U3").format.rowHeight = 6;
  sheet.getRange("A3:U3").format.fill.color = "#FFFFFF";

  // ── Row 4: Sub-section headers ────────────────────────────────────────────────
  const styleSubHdr = (range, text, cell) => {
    range.merge(false);
    sheet.getRange(cell).values = [[text]];
    sheet.getRange(cell).format.font.bold = true;
    sheet.getRange(cell).format.font.size = 9;
    sheet.getRange(cell).format.font.color = SUB_TEXT;
    sheet.getRange(cell).format.font.name = "Segoe UI";
    range.format.fill.color = SUB_BG;
    range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    range.format.verticalAlignment = Excel.VerticalAlignment.center;
    range.format.rowHeight = 18;
    setBorders(range);
  };
  styleSubHdr(sheet.getRange("A4:J4"), "HOURS BREAKDOWN BY REGION", "A4");
  styleSubHdr(sheet.getRange("L4:U4"), "PAY BREAKDOWN BY REGION", "L4");

  // ── Row 5: Year group headers ─────────────────────────────────────────────────
  const styleYrHdr = (mergeRange, cell, label, bg) => {
    mergeRange.merge(false);
    sheet.getRange(cell).values = [[label]];
    mergeRange.format.font.bold = true;
    mergeRange.format.font.size = 10;
    mergeRange.format.font.color = "white";
    mergeRange.format.font.name = "Segoe UI";
    mergeRange.format.fill.color = bg;
    mergeRange.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    mergeRange.format.verticalAlignment = Excel.VerticalAlignment.center;
    mergeRange.format.rowHeight = 18;
    setBorders(mergeRange);
  };

  // Hours side
  sheet.getRange("A5").format.fill.color = HDR_FILL;
  sheet.getRange("A5").format.rowHeight = 18;
  styleYrHdr(sheet.getRange("B5:D5"), "B5", "2025", YR25);
  styleYrHdr(sheet.getRange("E5:G5"), "E5", "2026", YR26);
  styleYrHdr(sheet.getRange("H5:J5"), "H5", "\u25B3 Change", YR_DELTA);

  // Pay side
  sheet.getRange("L5").format.fill.color = HDR_FILL;
  sheet.getRange("L5").format.rowHeight = 18;
  styleYrHdr(sheet.getRange("M5:O5"), "M5", "2025", YR25);
  styleYrHdr(sheet.getRange("P5:R5"), "P5", "2026", YR26);
  styleYrHdr(sheet.getRange("S5:U5"), "S5", "\u25B3 Change", YR_DELTA);

  // ── Row 6: Column headers ─────────────────────────────────────────────────────
  const styleColHdr = (range, label, bg) => {
    range.values = typeof label === "string" ? [[label]] : [label];
    range.format.font.bold = true;
    range.format.font.size = 8;
    range.format.font.color = "white";
    range.format.font.name = "Segoe UI";
    range.format.fill.color = bg;
    range.format.horizontalAlignment = Excel.HorizontalAlignment.center;
    range.format.verticalAlignment = Excel.VerticalAlignment.center;
    range.format.rowHeight = 18;
    setBorders(range);
  };

  // Hours col headers
  styleColHdr(sheet.getRange("A6"), "RR/DD", HDR_FILL);
  styleColHdr(sheet.getRange("B6:D6"), ["Total ST Hrs", "Total OT Hrs", "Total DT Hrs"], YR25);
  styleColHdr(sheet.getRange("E6:G6"), ["Total ST Hrs", "Total OT Hrs", "Total DT Hrs"], YR26);
  styleColHdr(
    sheet.getRange("H6:J6"),
    ["\u25B3 ST Hrs", "\u25B3 OT Hrs", "\u25B3 DT Hrs"],
    YR_DELTA
  );

  // Pay col headers
  styleColHdr(sheet.getRange("L6"), "RR/DD", HDR_FILL);
  styleColHdr(sheet.getRange("M6:O6"), ["Total ST Amt", "Total OT Amt", "Total DT Amt"], YR25);
  styleColHdr(sheet.getRange("P6:R6"), ["Total ST Amt", "Total OT Amt", "Total DT Amt"], YR26);
  styleColHdr(
    sheet.getRange("S6:U6"),
    ["\u25B3 ST Amt", "\u25B3 OT Amt", "\u25B3 DT Amt"],
    YR_DELTA
  );

  // ── Data Rows ─────────────────────────────────────────────────────────────────
  if (regions.length > 0) {
    const dataStart = 7;
    const dataEnd = 6 + regions.length;

    // Formatting helpers: negative → (val), zero → "-" for deltas, 0 for regular
    const addCommas = (n) => n.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    const fmtHrs = (v) => v < 0 ? `(${Math.abs(Math.round(v))})` : Math.round(v);
    const fmtPay = (v) => v < 0 ? `($${addCommas(Math.abs(Math.round(v)))})` : Math.round(v);
    const fmtDeltaH = (v) => v > 0 ? addCommas(Math.round(v)) : v < 0 ? `(${addCommas(Math.abs(Math.round(v)))})` : "-";
    const fmtDeltaP = (v) => v > 0 ? `$${addCommas(Math.round(v))}` : v < 0 ? `($${addCommas(Math.abs(Math.round(v)))})` : "-";

    const hoursRows = regions.map((g) => [
      g.region,
      fmtHrs(g.st25),
      fmtHrs(g.ot25),
      fmtHrs(g.dt25),
      fmtHrs(g.st26),
      fmtHrs(g.ot26),
      fmtHrs(g.dt26),
      fmtDeltaH(g.st26 - g.st25),
      fmtDeltaH(g.ot26 - g.ot25),
      fmtDeltaH(g.dt26 - g.dt25),
    ]);
    const payRows = regions.map((g) => [
      g.region,
      fmtPay(g.stPay25),
      fmtPay(g.otPay25),
      fmtPay(g.dtPay25),
      fmtPay(g.stPay26),
      fmtPay(g.otPay26),
      fmtPay(g.dtPay26),
      fmtDeltaP(g.stPay26 - g.stPay25),
      fmtDeltaP(g.otPay26 - g.otPay25),
      fmtDeltaP(g.dtPay26 - g.dtPay25),
    ]);

    // Format all data as text to preserve parentheses and leading zeros
    const textFmt = hoursRows.map(() => ["@","@","@","@","@","@","@","@","@","@"]);
    sheet.getRange(`A${dataStart}:J${dataEnd}`).numberFormat = textFmt;
    sheet.getRange(`L${dataStart}:U${dataEnd}`).numberFormat = textFmt;

    sheet.getRange(`A${dataStart}:J${dataEnd}`).values = hoursRows;
    sheet.getRange(`L${dataStart}:U${dataEnd}`).values = payRows;

    // Delta constants
    const DELTA_BG_POS  = "#FEE2E2"; // transparent red  (increase = bad for OT cost)
    const DELTA_BG_NEG  = "#DCFCE7"; // transparent green (decrease = good)
    const DELTA_BG_ZERO = "#DBEAFE"; // transparent blue  (no change)
    const DELTA_FG_POS  = "#DC2626"; // red text
    const DELTA_FG_NEG  = "#16A34A"; // green text
    const DELTA_FG_ZERO = "#2563EB"; // blue text
    const hoursDeltaCols = ["H", "I", "J"];
    const payDeltaCols   = ["S", "T", "U"];

    // Helper: style a delta cell (colors only — values already formatted in arrays)
    const styleDelta = (cell, val) => {
      cell.format.font.bold = true;
      if (val > 0) {
        cell.format.fill.color = DELTA_BG_POS;
        cell.format.font.color = DELTA_FG_POS;
      } else if (val < 0) {
        cell.format.fill.color = DELTA_BG_NEG;
        cell.format.font.color = DELTA_FG_NEG;
      } else {
        cell.format.fill.color = DELTA_BG_ZERO;
        cell.format.font.color = DELTA_FG_ZERO;
      }
    };

    // Single loop: alternating rows + delta coloring
    for (let i = 0; i < regions.length; i++) {
      const bg = i % 2 === 0 ? "#FFFFFF" : ALT_FILL;
      const row = dataStart + i;
      const r = regions[i];
      const hRow = sheet.getRange(`A${row}:J${row}`);
      const pRow = sheet.getRange(`L${row}:U${row}`);
      hRow.format.fill.color = bg;
      pRow.format.fill.color = bg;
      hRow.format.font.color = BODY_TEXT;
      pRow.format.font.color = BODY_TEXT;
      hRow.format.font.size = 10;
      pRow.format.font.size = 10;
      hRow.format.font.name = "Segoe UI";
      pRow.format.font.name = "Segoe UI";
      setBorders(hRow);
      setBorders(pRow);

      // Delta columns — hours
      const hDeltas = [r.st26 - r.st25, r.ot26 - r.ot25, r.dt26 - r.dt25];
      hoursDeltaCols.forEach((col, idx) => {
        styleDelta(sheet.getRange(`${col}${row}`), hDeltas[idx]);
      });
      // Delta columns — pay
      const pDeltas = [r.stPay26 - r.stPay25, r.otPay26 - r.otPay25, r.dtPay26 - r.dtPay25];
      payDeltaCols.forEach((col, idx) => {
        styleDelta(sheet.getRange(`${col}${row}`), pDeltas[idx]);
      });
    }

    // Number formats already set as text above; deltas handled by styleDelta

    // ── Totals Row ───────────────────────────────────────────────────────────
    const totalRow = dataEnd + 1;

    const writeTotals = (range, vals) => {
      range.values = [vals];
      range.format.font.bold = true;
      range.format.font.size = 10;
      range.format.font.color = KV_TEXT;
      range.format.font.name = "Segoe UI";
      range.format.fill.color = KV_FILL;
      setBorders(range);
    };

    // Format totals row as text
    sheet.getRange(`A${totalRow}:J${totalRow}`).numberFormat = [["@","@","@","@","@","@","@","@","@","@"]];
    sheet.getRange(`L${totalRow}:U${totalRow}`).numberFormat = [["@","@","@","@","@","@","@","@","@","@"]];

    writeTotals(sheet.getRange(`A${totalRow}:J${totalRow}`), [
      "TOTAL",
      fmtHrs(totals.st25),
      fmtHrs(totals.ot25),
      fmtHrs(totals.dt25),
      fmtHrs(totals.st26),
      fmtHrs(totals.ot26),
      fmtHrs(totals.dt26),
      fmtDeltaH(totals.st26 - totals.st25),
      fmtDeltaH(totals.ot26 - totals.ot25),
      fmtDeltaH(totals.dt26 - totals.dt25),
    ]);
    writeTotals(sheet.getRange(`L${totalRow}:U${totalRow}`), [
      "TOTAL",
      fmtPay(totals.stPay25),
      fmtPay(totals.otPay25),
      fmtPay(totals.dtPay25),
      fmtPay(totals.stPay26),
      fmtPay(totals.otPay26),
      fmtPay(totals.dtPay26),
      fmtDeltaP(totals.stPay26 - totals.stPay25),
      fmtDeltaP(totals.otPay26 - totals.otPay25),
      fmtDeltaP(totals.dtPay26 - totals.dtPay25),
    ]);

    // Totals row delta coloring — same rules as data rows
    const tHDeltas = [totals.st26 - totals.st25, totals.ot26 - totals.ot25, totals.dt26 - totals.dt25];
    const tPDeltas = [totals.stPay26 - totals.stPay25, totals.otPay26 - totals.otPay25, totals.dtPay26 - totals.dtPay25];
    hoursDeltaCols.forEach((col, idx) => {
      styleDelta(sheet.getRange(`${col}${totalRow}`), tHDeltas[idx]);
    });
    payDeltaCols.forEach((col, idx) => {
      styleDelta(sheet.getRange(`${col}${totalRow}`), tPDeltas[idx]);
    });

    // Thick dark outer border around both table sections
    setOuterBorder(sheet.getRange(`A1:J${totalRow}`));
    setOuterBorder(sheet.getRange(`L1:U${totalRow}`));
    // Thick top border on totals row to separate from data
    for (const edge of ["EdgeTop"]) {
      sheet.getRange(`A${totalRow}:J${totalRow}`).format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
      sheet.getRange(`A${totalRow}:J${totalRow}`).format.borders.getItem(edge).color = "#111827";
      sheet.getRange(`L${totalRow}:U${totalRow}`).format.borders.getItem(edge).style = Excel.BorderLineStyle.medium;
      sheet.getRange(`L${totalRow}:U${totalRow}`).format.borders.getItem(edge).color = "#111827";
    }
  } else {
    const noData = sheet.getRange("A7:U7");
    noData.merge(false);
    sheet.getRange("A7").values = [["No data found for this role."]];
    sheet.getRange("A7").format.font.italic = true;
    sheet.getRange("A7").format.font.color = "#999999";
  }

  // ── Column Widths ─────────────────────────────────────────────────────────────
  sheet.getRange("A:A").format.columnWidth = 52; // RR/DD hours
  sheet.getRange("B:J").format.columnWidth = 70; // hours data
  sheet.getRange("K:K").format.columnWidth = 16; // spacer
  sheet.getRange("L:L").format.columnWidth = 52; // RR/DD pay
  sheet.getRange("M:U").format.columnWidth = 70; // pay data
  sheet.getRange("W:W").columnHidden = true; // 2025 week options (hidden)
  sheet.getRange("X:X").columnHidden = true; // 2026 week options (hidden)

  // ── Vertical alignment ────────────────────────────────────────────────────────
  sheet.getUsedRange().format.verticalAlignment = Excel.VerticalAlignment.center;

  // ── Horizontal alignment ──────────────────────────────────────────────────────
  sheet.getRange("A:A").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("L:L").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("B:J").format.horizontalAlignment = Excel.HorizontalAlignment.right;
  sheet.getRange("M:U").format.horizontalAlignment = Excel.HorizontalAlignment.right;

  // Re-center merged header rows
  sheet.getRange("A1:U1").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("H2:J2").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("A4:J4").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("L4:U4").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("B5:D5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("E5:G5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("H5:J5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("M5:O5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("P5:R5").format.horizontalAlignment = Excel.HorizontalAlignment.center;
  sheet.getRange("S5:U5").format.horizontalAlignment = Excel.HorizontalAlignment.center;

  sheet.tabColor = TITLE_BG;
  sheet.freezePanes.freezeRows(6);

  await context.sync();
}

// ─── STEP 3: BUILD MECHANIC BASE PIVOT ───────────────────────────────────────
export async function buildMechanicBasePivot(rawData) {
  _pivotFilterBusy++;
  try {
    await Excel.run(async (context) => {
      const data = rawData || await readRawData(context);
      await writeProfessionalPivot(context, "MechanicBASE_Pivot", ROLE_MECH_BASE, data);

      // Register pivot filter event handler (once per session)
      if (!_pivotEventRegistered) {
        const pivotSheet = context.workbook.worksheets.getItem("MechanicBASE_Pivot");
        pivotSheet.onChanged.add(handlePivotFilterChange);
        _pivotEventRegistered = true;
        await context.sync();
      }
    });
  } finally {
    _pivotFilterBusy--;
  }
}

// ─── PIVOT FILTER CHANGE HANDLER ─────────────────────────────────────────────
async function handlePivotFilterChange(args) {
  if (_pivotFilterBusy > 0) return;

  // Only react to changes in week filter cells B2 (2025) or E2 (2026)
  const addr = (args.address || "").replace(/\$/g, "").toUpperCase();
  if (addr !== "B2" && addr !== "E2") return;

  _pivotFilterBusy++;
  try {
    let needsRebuild = false;
    await Excel.run(async (context) => {
      const sheet = context.workbook.worksheets.getItem("MechanicBASE_Pivot");
      const b2 = sheet.getRange("B2");
      const e2 = sheet.getRange("E2");
      b2.load("values");
      e2.load("values");
      await context.sync();

      const newWeek25 = (b2.values[0][0] || "").toString().trim();
      const newWeek26 = (e2.values[0][0] || "").toString().trim();

      if (addr === "B2" && newWeek25 !== _pivotWeek25 && newWeek25 !== "No data") {
        _pivotWeek25 = newWeek25;
        needsRebuild = true;
      } else if (addr === "E2" && newWeek26 !== _pivotWeek26 && newWeek26 !== "No data") {
        _pivotWeek26 = newWeek26;
        needsRebuild = true;
      }
    });

    if (needsRebuild) {
      await buildMechanicBasePivot(_allData && _allData.length > 0 ? _allData : null);
    }
  } catch (err) {
    console.error("Pivot filter change error:", err);
  } finally {
    _pivotFilterBusy--;
  }
}

// ─── SHARED: READ RAW DATA (batched + aggregated for large datasets) ─────────
async function readRawData(context) {
  const sheet = context.workbook.worksheets.getItem("Sheet1");
  const usedRange = sheet.getUsedRange();
  usedRange.load("rowCount,columnCount");
  await context.sync();

  const totalRows = usedRange.rowCount;
  if (totalRows < 2) return [];

  // Smaller batches to stay within Office.js payload limits (~5MB per sync)
  // 26 cols × 2000 rows ≈ safe payload size
  const BATCH = 2000;
  const numCols = Math.min(usedRange.columnCount, NUM_RAW_COLS);
  const totalBatches = Math.ceil((totalRows - 1) / BATCH);
  let skipped = 0;
  let rawRowCount = 0;

  // Aggregate on-the-fly by (region, role, name, ppeDate) to reduce memory
  // Key: "region||role||name||ppeDateTimestamp"
  const aggregated = {};

  for (let start = 1; start < totalRows; start += BATCH) {
    const batchNum = Math.floor((start - 1) / BATCH) + 1;

    // Show progress for large datasets
    if (totalRows > 10000) {
      showMessage(`Reading data: batch ${batchNum}/${totalBatches} (${Math.round((start / (totalRows - 1)) * 100)}%)…`);
    }

    const count = Math.min(BATCH, totalRows - start);
    const chunk = sheet.getRangeByIndexes(start, 0, count, numCols);
    chunk.load("values");
    await context.sync();

    const vals = chunk.values;
    for (let i = 0; i < vals.length; i++) {
      const r = vals[i];
      const role = (r[COL.ROLE] || "").toString().trim();
      if (!role) continue;

      const ppeDate = excelDateToDate(r[COL.PPE_DATE]);
      if (!ppeDate) { skipped++; continue; }

      rawRowCount++;
      const region = (r[COL.REGION] || "").toString().trim();
      const name = (r[COL.NAME] || "").toString().trim();
      const key = `${region}||${role}||${name}||${ppeDate.getTime()}`;

      if (!aggregated[key]) {
        aggregated[key] = {
          region,
          role,
          name,
          ppeDate,
          st: 0, ot: 0, dt: 0,
          stPay: 0, otPay: 0, dtPay: 0,
        };
      }
      const agg = aggregated[key];
      agg.st += toNum(r[COL.ST]);
      agg.ot += toNum(r[COL.OT]);
      agg.dt += toNum(r[COL.DT]);
      agg.stPay += toNum(r[COL.ST_PAY]);
      agg.otPay += toNum(r[COL.OT_PAY]);
      agg.dtPay += toNum(r[COL.DT_PAY]);
    }
  }

  const result = Object.values(aggregated);

  if (skipped > 0) console.warn(`readRawData: skipped ${skipped} rows with missing/invalid PPE Date`);
  console.log(`readRawData: loaded ${rawRowCount} rows → ${result.length} aggregated entries from ${totalRows - 1} total (in ${totalBatches} batches)`);

  if (totalRows > 10000) {
    showMessage(`Loaded ${rawRowCount.toLocaleString()} rows → ${result.length.toLocaleString()} grouped entries. Processing…`);
  }

  return result;
}

// ─── SHARED: WRITE PIVOT SHEET ────────────────────────────────────────────────
async function writePivotSheet(context, sheetName, rows) {
  const sheets = context.workbook.worksheets;
  sheets.load("items/name");
  await context.sync();

  let sheet;
  const exists = sheets.items.some((s) => s.name === sheetName);
  if (exists) {
    sheet = sheets.getItem(sheetName);
    sheet.getUsedRange().clear();
  } else {
    sheet = sheets.add(sheetName);
  }

  // Group by Name + PPE Date
  const groups = {};
  for (const r of rows) {
    const key = `${r.name}||${r.ppeDate.getTime()}`;
    if (!groups[key]) {
      groups[key] = {
        name: r.name,
        ppeDate: r.ppeDate,
        st: 0,
        ot: 0,
        dt: 0,
        stPay: 0,
        otPay: 0,
        dtPay: 0,
      };
    }
    const g = groups[key];
    g.st += r.st;
    g.ot += r.ot;
    g.dt += r.dt;
    g.stPay += r.stPay;
    g.otPay += r.otPay;
    g.dtPay += r.dtPay;
  }

  const sorted = Object.values(groups).sort((a, b) => b.ppeDate - a.ppeDate);

  const headers = [
    "Name",
    "PPE Date",
    "ST Hrs",
    "OT Hrs",
    "DT Hrs",
    "Total Hrs",
    "ST Pay",
    "OT Pay",
    "DT Pay",
    "Total Pay",
  ];
  const headerRange = sheet.getRange("A1:J1");
  headerRange.values = [headers];
  headerRange.format.font.bold = true;
  headerRange.format.fill.color = "#1F3864";
  headerRange.format.font.color = "white";

  if (sorted.length === 0) {
    await context.sync();
    return;
  }

  const dataRows = sorted.map((g) => [
    g.name,
    dateToExcelSerial(g.ppeDate),
    g.st,
    g.ot,
    g.dt,
    g.st + g.ot + g.dt,
    g.stPay,
    g.otPay,
    g.dtPay,
    g.stPay + g.otPay + g.dtPay,
  ]);

  // Write in batches to avoid Office.js payload limits
  const WRITE_BATCH = 5000;
  for (let i = 0; i < dataRows.length; i += WRITE_BATCH) {
    const batch = dataRows.slice(i, i + WRITE_BATCH);
    const startRow = 2 + i;
    const endRow = startRow + batch.length - 1;
    sheet.getRange(`A${startRow}:J${endRow}`).values = batch;
    await context.sync();
  }

  // Format PPE Date and pay columns — each column separately
  const lastRow = 1 + dataRows.length;
  sheet.getRange(`B2:B${lastRow}`).numberFormat = [["mm/dd/yyyy"]];
  sheet.getRange(`G2:G${lastRow}`).numberFormat = [["$#,##0.00"]];
  sheet.getRange(`H2:H${lastRow}`).numberFormat = [["$#,##0.00"]];
  sheet.getRange(`I2:I${lastRow}`).numberFormat = [["$#,##0.00"]];
  sheet.getRange(`J2:J${lastRow}`).numberFormat = [["$#,##0.00"]];

  await context.sync();
}

